package ui

// Layout height constants for UI sections.
const (
	// Optional content elements inside session box
	TableHeaderHeight     = 1
	TableDottedLineHeight = 1

	// Pinned self session (row + separator)
	SelfSessionOverhead = 2

	// Bottom action bar height (2 rows × 2 lines each + 1 gap line)
	ActionBarHeight = 5

	// Fallback values
	DefaultVisibleItems = 10
)

}

func TestContentHeight(t *testing.T) {
	tests := []struct {
		name   string
		height int
		want   int
	}{
		{
			name:   "zero height returns zero",
			height: 0,
			want:   0,
		},
		{
			name:   "normal height subtracts border overhead",
			height: 30,
			want:   28, // 30 - 2 (AppBorderOverheadY)
		},
		{
			name:   "small height",
			height: 10,
			want:   8, // 10 - 2
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			m := Model{height: tt.height}
			got := m.contentHeight()
			if got != tt.want {
				t.Errorf("contentHeight() with height=%d = %d, want %d", tt.height, got, tt.want)
			}
		})
	}
}

func TestSessionMaxVisibleItems(t *testing.T) {
	tests := []struct {
		name   string
		height int
		want   int
	}{
		{
			name:   "zero height returns fallback",
			height: 0,
			want:   10,
		},
		{
			name:   "small window",
			height: 12, // contentHeight = 10, overhead = 6 + ActionBarHeight(1) = 7, available = 3 → capped at 10
			want:   10,
		},
		{
			name:   "large window capped at 10",
			height: 50, // contentHeight = 48, overhead = 11, available = 37 → capped at 10
			want:   10,
		},
		{
			name:   "very small window",
			height: 10, // contentHeight = 8, overhead = 11, available = -3 → fallback
			want:   10,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			cfg := config.DefaultConfig()
			m := Model{
				height: tt.height,
				config: cfg,
			}
			got := m.sessionMaxVisibleItems()
			if got != tt.want {
				t.Errorf("sessionMaxVisibleItems() with height=%d = %d, want %d",
					tt.height, got, tt.want)
			}
		})
	}
}

func TestProjectMaxVisibleItems(t *testing.T) {
	tests := []struct {
		name   string
		height int
		want   int
	}{
		{
			name:   "zero height returns fallback",
			height: 0,
			want:   10,
		},
		{
			name:   "small window",
			height: 12, // contentHeight = 10, overhead = 6 + 5 = 11, available = -1 → fallback
			want:   10,
		},
		{
			name:   "large window capped at 10",
			height: 50, // contentHeight = 48, overhead = 11, available = 37 → capped at 10
			want:   10,
		},
		{
			name:   "medium window",
			height: 17, // contentHeight = 15, overhead = 11, available = 4
			want:   4,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			cfg := config.DefaultConfig()
			m := Model{
				height: tt.height,
				config: cfg,
			}
			got := m.projectMaxVisibleItems()
			if got != tt.want {
				t.Errorf("projectMaxVisibleItems() with height=%d = %d, want %d",
					tt.height, got, tt.want)
			}
		})
	}
}

	contentH := m.contentHeight()
	if contentH > 0 {
		// Header: 3 (title + prompt + border)
		// Footer: 3 (border + notification + hints)
		// Action bar: 5 (2 rows × 2 lines + 1 gap)
		// Total base: 11
		overhead := 6 + ui.ActionBarHeight
		if m.sessionsLoaded && len(m.items) > 0 {
			overhead += ui.TableHeaderHeight + ui.TableDottedLineHeight // +2 = 8
		}
		// Self session row + separator are pinned, not scrollable
		if m.selfSession != nil {
			overhead += ui.SelfSessionOverhead
		}
		if available := contentH - overhead; available > 0 {
			if available > ui.DefaultVisibleItems {
				return ui.DefaultVisibleItems
			}
			return available
		}
	}
	return ui.DefaultVisibleItems
}

// projectMaxVisibleItems returns the actual number of items that can be shown
// based on window height, matching the View's calculation
func (m *Model) projectMaxVisibleItems() int {
	contentH := m.contentHeight()
	if contentH > 0 {
		if available := contentH - 6 - ui.ActionBarHeight; available > 0 { // header(3) + footer(3) + actionBar(5)
			if available > ui.DefaultVisibleItems {
				return ui.DefaultVisibleItems
			}
			return available
		}
	}
	return ui.DefaultVisibleItems
}

